    function isAuthenticated(){var s=load(KEY_SESSION),e=load(KEY_SESSION_EXP),h=load(KEY_HASH);if(!s||!e||!h)return false;if(Date.now()>Number(e)){remove(KEY_SESSION);remove(KEY_SESSION_EXP);return false}return true}
    function today(){var d=new Date();return[d.getFullYear(),String(d.getMonth()+1).padStart(2,'0'),String(d.getDate()).padStart(2,'0')].join('-')}
