    function parseFM(raw){var m=raw.match(/^---\r?\n([\s\S]*?)\r?\n---\r?\n?([\s\S]*)$/);if(!m)return{meta:{},content:raw};var meta={};m[1].split(/\r?\n/).forEach(function(line){if(!line.trim())return;var i=line.indexOf(':');if(i===-1)return;var k=line.slice(0,i).trim(),v=line.slice(i+1).trim();if((v.startsWith('"')&&v.endsWith('"'))||(v.startsWith("'")&&v.endsWith("'")))v=v.slice(1,-1);if(v==='true')v=true;else if(v==='false')v=false;else if(v.startsWith('[')&&v.endsWith(']'))v=v.slice(1,-1).split(',').map(function(s){return s.trim().replace(/^['"]|['"]$/g,'')}).filter(Boolean);meta[k]=v});return{meta:meta,content:m[2].replace(/^\n+/,'')}}
    function fmVal(v){if(v===true||v===false)return String(v);if(Array.isArray(v))return'['+v.join(', ')+']';return'"'+String(v).replace(/"/g,'\\"')+'"'}
