    async function ghRequest(method,path,body){var token=load(KEY_TOKEN);if(!token)throw new Error('No GitHub token. Go to Settings and add your token.');var res=await fetch('https://api.github.com/repos/'+REPO_OWNER+'/'+REPO_NAME+'/contents/'+path,{method:method,headers:{Authorization:'Bearer '+token,Accept:'application/vnd.github.v3+json','Content-Type':'application/json'},body:body?JSON.stringify(body):undefined});if(!res.ok){var err=await res.json().catch(function(){return{message:res.statusText}});throw new Error(err.message||('GitHub API error: '+res.status))}return res.status===204?null:res.json()}
