    async function initAuth(){var box=document.getElementById('auth-content');if(!load(KEY_HASH)){box.innerHTML='<div class="alert alert-info"><strong>First-time setup</strong><br>Set a password and add your GitHub token.</div><div id="setup-alert"></div><div class="fg"><label>Admin Password</label><input type="password" id="setup-pwd"></div><div class="fg"><label>Confirm Password</label><input type="password" id="setup-confirm"></div><div class="fg"><label>GitHub Personal Access Token</label><input type="password" id="setup-token" placeholder="ghp_..."></div><button class="btn p full" type="button" data-action="do-setup">Set Up Admin Panel</button>'}else{box.innerHTML='<div id="login-alert"></div><div class="fg"><label>Password</label><input type="password" id="login-pwd" data-enter-action="do-login"></div><button class="btn p full" type="button" data-action="do-login">Login</button>'}}
    async function doSetup(){var p=document.getElementById('setup-pwd').value,c=document.getElementById('setup-confirm').value,t=document.getElementById('setup-token').value.trim();if(!p)return showAlert('setup-alert','error','Password is required.');if(p!==c)return showAlert('setup-alert','error','Passwords do not match.');if(!t)return showAlert('setup-alert','error','GitHub token is required.');store(KEY_HASH,await sha256(p));store(KEY_TOKEN,t);createSession();enterAdmin()}
