    function setNavMenuOpen(isOpen){var els=navEls(),open=isDesktopNav()?true:!!isOpen;if(!els.nav||!els.toggle)return;els.nav.classList.toggle('is-open',open);els.toggle.setAttribute('aria-expanded',String(open&&!isDesktopNav()))}
