    function setNav(name){['dashboard','posts','portfolio','pages','media','settings'].forEach(function(id){var el=document.getElementById('nav-'+id),active=id===name;if(!el)return;el.classList.toggle('p',active);el.classList.toggle('g',!active);el.setAttribute('aria-pressed',String(active))})}
