    function showSection(name){sections.forEach(function(s){var el=document.getElementById('sec-'+s);if(el)el.classList.add('hidden')});var cur=document.getElementById('sec-'+name);if(cur)cur.classList.remove('hidden');store('admin_last_section',name);if(['dashboard','posts','portfolio','pages','media','settings'].indexOf(name)!==-1)setNav(name);closeNavMenu();if(name==='dashboard')refreshDashboard();if(name==='posts')loadPosts();if(name==='portfolio')loadPortfolio();if(name==='media')loadMedia();if(name==='settings')prefillSettings()}
    function postStatus(meta){var d=String(meta.date||today()).slice(0,10);if(meta.status==='draft'||meta.published===false)return'draft';if(meta.status==='scheduled'||d>today())return'scheduled';return'published'}
    function statusPill(s){return'<span class="pill '+s+'">'+esc(s.charAt(0).toUpperCase()+s.slice(1))+'</span>'}
    function postUrl(name){var c=String(name).replace('.md',''),dp=c.slice(0,10).split('-'),slug=c.slice(11);return'/'+dp.join('/')+'/'+slug+'/'}
    async function ensurePostHydrated(post){if(post&&post.meta&&typeof post.content!=='undefined'&&post.status)return post;var full=await ghGetFile(post.path),p=parseFM(full.raw);post.raw=full.raw;post.sha=full.sha;post.meta=p.meta;post.content=p.content;post.status=postStatus(p.meta);return post}
    async function ensurePostsHydrated(items){if(!items||!items.length)return items;for(var i=0;i<items.length;i++)await ensurePostHydrated(items[i]);return items}
    function setPostsPage(page){currentPostsPage=Math.max(1,Number(page)||1);store(KEY_POSTS_PAGE,String(currentPostsPage))}
    async function loadPosts(){var wrap=document.getElementById('posts-wrap');wrap.innerHTML='<div class="loading"><span class="spin"></span> Loading posts...</div>';try{var files=await ghList(POSTS_DIR);postsCache=files.filter(function(f){return f.name.endsWith('.md')}).sort(function(a,b){return String(b.name||'').localeCompare(String(a.name||''))});currentPostsPage=loadPositiveInt(KEY_POSTS_PAGE,currentPostsPage);postsHydratedAll=false;await renderPostsList()}catch(err){wrap.innerHTML='<div class="alert alert-error">'+esc(err.message)+'</div>'}}
    function uiIcon(name){return'<svg class="ui-icon" aria-hidden="true"><use href="#icon-'+name+'"></use></svg>'}
    function postsPager(total,page){var pages=Math.max(1,Math.ceil(total/POSTS_PER_PAGE)),buttons='',start=Math.max(1,page-2),end=Math.min(pages,start+4);if(end-start<4)start=Math.max(1,end-4);for(var i=start;i<=end;i++)buttons+='<button class="btn sm g'+(i===page?' pager-current':'')+'" type="button" data-action="posts-page" data-page="'+i+'"'+(i===page?' aria-current="page"':'')+'>'+i+'</button>';return'<div class="posts-toolbar"><p class="muted">Showing '+(total?(((page-1)*POSTS_PER_PAGE)+1):0)+'-'+Math.min(total,page*POSTS_PER_PAGE)+' of '+total+' posts</p><div class="posts-pagination"><button class="btn sm g" type="button" data-action="posts-page" data-page="'+Math.max(1,page-1)+'"'+(page===1?' disabled':'')+'>Prev</button>'+buttons+'<button class="btn sm g" type="button" data-action="posts-page" data-page="'+Math.min(pages,page+1)+'"'+(page===pages?' disabled':'')+'>Next</button></div></div>'}
    async function renderPostsList(){var wrap=document.getElementById('posts-wrap'),q=(document.getElementById('post-search').value||'').toLowerCase(),f=document.getElementById('post-filter').value,items=postsCache.slice();if(q||f!=='all'){if(!postsHydratedAll){wrap.innerHTML='<div class="loading"><span class="spin"></span> Filtering posts...</div>';await ensurePostsHydrated(postsCache);postsHydratedAll=true}items=postsCache.filter(function(p){var hay=((p.meta.title||'')+' '+p.name).toLowerCase();return(!q||hay.indexOf(q)!==-1)&&(f==='all'||p.status===f)})}var totalPages=Math.max(1,Math.ceil(items.length/POSTS_PER_PAGE));if(currentPostsPage>totalPages)setPostsPage(totalPages);else setPostsPage(currentPostsPage);var pageItems=items.slice((currentPostsPage-1)*POSTS_PER_PAGE,currentPostsPage*POSTS_PER_PAGE);await ensurePostsHydrated(pageItems);if(!items.length){wrap.innerHTML='<div class="card"><p class="muted">No posts match the current filters.</p></div>';return}wrap.innerHTML=postsPager(items.length,currentPostsPage)+'<div class="posts">'+pageItems.map(function(p){return'<div class="post"><div class="info"><div class="title">'+esc(p.meta.title||p.name)+' '+statusPill(p.status)+'</div><div class="meta">'+esc(String(p.meta.date||'').slice(0,10))+' | '+esc(p.name)+' | <a href="'+esc(postUrl(p.name))+'" target="_blank" rel="noopener">View</a></div></div><div class="actions"><button class="btn sm has-icon" type="button" data-action="edit-post" data-path="'+esc(p.path)+'">'+uiIcon('edit')+'<span>Edit</span></button><button class="btn d sm has-icon" type="button" data-action="remove-post" data-path="'+esc(p.path)+'">'+uiIcon('trash')+'<span>Delete</span></button></div></div>'}).join('')+'</div>'+postsPager(items.length,currentPostsPage)}
    function changePostsPage(page){setPostsPage(page);renderPostsList()}
    function onPostFiltersChanged(){setPostsPage(1);renderPostsList()}
    function autoPostFile(title,date){return(date||today())+'-'+slugify(title||'post')+'.md'}
    function postValues(){return{title:document.getElementById('pe-title').value.trim(),date:document.getElementById('pe-date').value||today(),categories:document.getElementById('pe-cats').value.trim(),tags:document.getElementById('pe-tags').value.trim(),youtube:document.getElementById('pe-youtube').value.trim(),desc:document.getElementById('pe-desc').value.trim(),seoTitle:document.getElementById('pe-seo-title').value.trim(),social:document.getElementById('pe-social').value.trim(),canonical:document.getElementById('pe-canonical').value.trim(),file:document.getElementById('pe-file').value.trim(),content:document.getElementById('pe-content').value,status:document.getElementById('pe-status').value}}
