    function setPostValues(v){v=v||{title:'',date:today(),categories:'',tags:'',youtube:'',desc:'',seoTitle:'',social:'',canonical:'',file:'',content:'',status:'draft'};suspendPostAutosave=true;document.getElementById('pe-title').value=v.title||'';document.getElementById('pe-date').value=v.date||today();document.getElementById('pe-cats').value=v.categories||'';document.getElementById('pe-tags').value=v.tags||'';document.getElementById('pe-youtube').value=v.youtube||'';document.getElementById('pe-desc').value=v.desc||'';document.getElementById('pe-seo-title').value=v.seoTitle||'';document.getElementById('pe-social').value=v.social||'';document.getElementById('pe-canonical').value=v.canonical||'';document.getElementById('pe-file').value=v.file||'';document.getElementById('pe-content').value=v.content||'';document.getElementById('pe-status').value=v.status||'draft';lastAutoPostFile=v.file||autoPostFile(v.title,v.date);suspendPostAutosave=false;syncPostEditor()}
    function openPostEditor(){currentPost=null;remove(KEY_POST_AUTOSAVE);document.getElementById('post-editor-title').textContent='New Post';showSection('post-editor');setPostTemplateMode(true);setPostValues()}
    async function editPost(path){try{var f=await ghGetFile(path),p=parseFM(f.raw);currentPost={path:path,sha:f.sha,file:path.split('/').pop()};remove(KEY_POST_AUTOSAVE);document.getElementById('post-editor-title').textContent='Edit Post';showSection('post-editor');setPostTemplateMode(false);setPostValues({title:p.meta.title||'',date:String(p.meta.date||today()).slice(0,10),categories:Array.isArray(p.meta.categories)?p.meta.categories.join(', '):String(p.meta.categories||'').replace(/[\[\]]/g,''),tags:Array.isArray(p.meta.tags)?p.meta.tags.join(', '):String(p.meta.tags||'').replace(/[\[\]]/g,''),youtube:p.meta.youtube_id||'',desc:p.meta.description||'',seoTitle:p.meta.seo_title||'',social:p.meta.social_image||'',canonical:p.meta.canonical_url||'',file:currentPost.file,content:p.content,status:postStatus(p.meta)})}catch(err){showAlert('posts-wrap','error',esc(err.message))}}
    function applyTemplate(name){var v=postValues(),titleAuto=autoPostFile(v.title,v.date);if(name==='blank'){document.getElementById('pe-title').value='';document.getElementById('pe-cats').value='';document.getElementById('pe-tags').value='';document.getElementById('pe-youtube').value='';document.getElementById('pe-desc').value='';document.getElementById('pe-seo-title').value='';document.getElementById('pe-social').value='';document.getElementById('pe-canonical').value='';document.getElementById('pe-content').value='';if(!v.file||v.file===titleAuto||v.file===lastAutoPostFile)document.getElementById('pe-file').value='';syncPostEditor();return}var t=templates[name];if(!t)return;document.getElementById('pe-title').value=t.title;document.getElementById('pe-cats').value=t.categories;document.getElementById('pe-tags').value=t.tags;document.getElementById('pe-desc').value=t.excerpt;document.getElementById('pe-content').value=t.content;document.getElementById('pe-youtube').value='';document.getElementById('pe-seo-title').value='';document.getElementById('pe-social').value='';document.getElementById('pe-canonical').value='';if(!v.file||v.file===titleAuto||v.file===lastAutoPostFile)document.getElementById('pe-file').value='';syncPostEditor()}
    function onPostStatus(){if(document.getElementById('pe-status').value==='scheduled'&&document.getElementById('pe-date').value<=today()){var d=new Date();d.setDate(d.getDate()+2);document.getElementById('pe-date').value=[d.getFullYear(),String(d.getMonth()+1).padStart(2,'0'),String(d.getDate()).padStart(2,'0')].join('-')}syncPostEditor()}
    function syncPostEditor(){var v=postValues(),autoFile=autoPostFile(v.title,v.date),fileField=document.getElementById('pe-file');if(!fileField.value.trim()||fileField.value.trim()===lastAutoPostFile)fileField.value=autoFile;lastAutoPostFile=fileField.value.trim()||autoFile;document.getElementById('pe-slug').textContent=postUrl(lastAutoPostFile);if(!suspendPostAutosave&&!currentPost)store(KEY_POST_AUTOSAVE,JSON.stringify(postValues()));refreshPostPreview();updatePostChecklist()}
    async function ensurePreviewData(includePosts){if(!siteCache.configRaw){try{var cfg=await ghGetFile(CONFIG_FILE);siteCache.configRaw=cfg.raw;siteCache.configSha=cfg.sha}catch(e){}}if(includePosts&&!postsCache.length){try{await loadPosts()}catch(e){}}if(includePosts&&postsCache.length&&!postsHydratedAll){try{await ensurePostsHydrated(postsCache);postsHydratedAll=true}catch(e){}}}
    function configMap(){var raw=siteCache.configRaw||'',keys=['title','description','author','author_fullname','email','lang','timezone','url','baseurl','logo','profile_image','github_username','twitter_username','facebook_url','youtube_channel'];return keys.reduce(function(map,key){map[key]=yamlVal(raw,key)||'';return map},{})}
    function stripHtmlText(text){return String(text||'').replace(/<[^>]*>/g,' ').replace(/\s+/g,' ').trim()}
    function truncateWords(text,count){var words=String(text||'').trim().split(/\s+/).filter(Boolean);return words.length>count?words.slice(0,count).join(' ')+'...':words.join(' ')}
    function formatPreviewDate(value,mode){var d=new Date(value);if(isNaN(d.getTime()))return String(value||'');if(mode==='xml'){return d.toISOString()}var months=['January','February','March','April','May','June','July','August','September','October','November','December'];return months[d.getMonth()]+' '+d.getDate()+', '+d.getFullYear()}
    function excerptForPost(post){return post.meta.description||truncateWords(stripHtmlText(post.content||''),30)}
    function postWordCount(text){return String(text||'').trim().split(/\s+/).filter(Boolean).length}
    function headingCount(text){var m=String(text||'').match(/^##?\s+/gm);return m?m.length:0}
    function normalizedTitleKey(text){return slugify(String(text||'').replace(/\b(lyrics|karaoke|official|video)\b/gi,' ').replace(/\s+/g,' ').trim())}
    function resolvePath(path){var cfg=configMap(),base=cfg.baseurl||'';return (base&&base!=='/'?base:'')+path}
    function resolveValue(expr,context){expr=expr.trim();if((expr.startsWith("'")&&expr.endsWith("'"))||(expr.startsWith('"')&&expr.endsWith('"')))return expr.slice(1,-1);if(expr==='site.posts.size')return String(postsCache.length);if(expr==='tag')return context.tag||'';var parts=expr.split('.'),root=parts.shift();var source=root==='site'?configMap():root==='page'?(context.page||{}):root==='post'?(context.post||{}):root==='tag'?context.tag||'':{};var value=source;for(var i=0;i<parts.length;i++){if(value==null)break;value=value[parts[i]]}return value==null?'':value}
    function applyFilters(value,filters){var out=value;for(var i=0;i<filters.length;i++){var filter=filters[i].trim();if(filter==='relative_url')out=resolvePath(String(out||''));else if(filter==='absolute_url'){var cfg=configMap();out=(cfg.url||'')+resolvePath(String(out||''))}else if(filter==='strip_html')out=stripHtmlText(out);else if(filter.indexOf('truncatewords:')===0)out=truncateWords(out,parseInt(filter.split(':')[1],10)||30);else if(filter==='date_to_xmlschema')out=formatPreviewDate(out,'xml');else if(filter.indexOf('date:')===0)out=formatPreviewDate(out,'text')}return out}
