    function health(posts,pages){var issues=[],seen={};posts.forEach(function(p){var t=String(p.meta.title||'').trim(),key=normalizedTitleKey(t),words=postWordCount(p.content||'');if(!t)issues.push({t:'Missing title',d:p.name});if(!p.meta.description)issues.push({t:'Missing description',d:p.name});if(words<180)issues.push({t:'Thin post draft',d:(p.meta.title||p.name)+' is under 180 words.'});if(!(Array.isArray(p.meta.tags)?p.meta.tags.length:String(p.meta.tags||'').trim()))issues.push({t:'Missing tags',d:p.name});if(t){if(seen[key])issues.push({t:'Duplicate title pattern',d:t});seen[key]=1}});var known=Object.keys(PAGE_FILES).map(function(k){return'/'+PAGE_FILES[k].replace(/\.md$/,'/').replace(/index\.html$/,'')}).concat(posts.map(function(p){return postUrl(p.name)}));posts.concat(pages).forEach(function(x){links(x.content||'').forEach(function(l){if(l.startsWith('/')&&!l.startsWith('/assets/')&&known.every(function(r){return l.indexOf(r)!==0}))issues.push({t:'Possible broken internal link',d:l+' in '+(x.name||x.path||x.key)})})});['privacy','disclosure','editorial','terms','contact','about'].forEach(function(key){if(!pages.some(function(p){return p.key===key}))issues.push({t:'Missing trust page',d:key+' page is not being tracked.'})});var drafts=posts.filter(function(p){return p.status==='draft'});if(drafts.length)issues.push({t:'Draft posts pending review',d:drafts.length+' draft(s) found.'});return issues.slice(0,12)}
    function renderDashboard(posts,pages,pf){var pub=posts.filter(function(p){return p.status==='published'}).length,dr=posts.filter(function(p){return p.status==='draft'}).length,sch=posts.filter(function(p){return p.status==='scheduled'}).length,words=posts.reduce(function(s,p){return s+String(p.content||'').split(/\s+/).filter(Boolean).length},0);document.getElementById('dash-stats').innerHTML=[stat('Published Posts',pub),stat('Drafts',dr),stat('Scheduled',sch),stat('Pages',pages.length),stat('Portfolio Items',pf.length),stat('Words Published',words)].join('');var hs=health(posts,pages);document.getElementById('dash-health').innerHTML=hs.length?hs.map(function(i){return item(i.t,i.d)}).join(''):item('All clear','No health issues found.');document.getElementById('dash-analytics').innerHTML=[item('Average words per post',posts.length?Math.round(words/posts.length):0),item('Posts with meta descriptions',posts.filter(function(p){return p.meta.description}).length+' of '+posts.length),item('Posts with social images',posts.filter(function(p){return p.meta.social_image}).length+' of '+posts.length)].join('');document.getElementById('dash-summary').innerHTML=[item('Latest post',posts[0]?(posts[0].meta.title||posts[0].name):'No posts yet'),item('Indexable pages',pages.filter(function(p){return p.meta.noindex!==true}).length),item('Tracked policy pages',pages.map(function(p){return p.key}).join(', '))].join('')}
    async function exportBackup(type){if(type==='posts'&&!postsHydratedAll){await ensurePostsHydrated(postsCache);postsHydratedAll=true}var payload;if(type==='posts')payload=postsCache.map(function(p){return{path:p.path,meta:p.meta,content:p.content}});else if(type==='portfolio')payload=portfolioCache;else if(type==='pages')payload=Object.keys(PAGE_FILES);else if(type==='settings')payload=siteCache;else payload={posts:postsCache,portfolio:portfolioCache,settings:siteCache,exportedAt:new Date().toISOString()};var blob=new Blob([JSON.stringify(payload,null,2)],{type:'application/json;charset=utf-8'}),url=URL.createObjectURL(blob),a=document.createElement('a');a.href=url;a.download='metaxenopy-'+type+'-backup.json';a.click();URL.revokeObjectURL(url)}
    function yamlVal(raw,key){var re=new RegExp('^'+key.replace(/[.*+?^${}()|[\]\\]/g,'\\$&')+':\\s*"?([^"\\n]*)"?$','m'),m=raw.match(re);return m?m[1]:''}
    function yamlSet(raw,key,val){var re=new RegExp('^'+key.replace(/[.*+?^${}()|[\]\\]/g,'\\$&')+':\\s*.*$','m'),line=key+': "'+String(val||'').replace(/"/g,'\\"')+'"';return re.test(raw)?raw.replace(re,line):raw.trimEnd()+'\n'+line+'\n'}
    function normalizePath(path){var value=String(path||'').trim();if(!value)return'';return value.charAt(0)==='/'?value:'/'+value}
    function cacheBust(path){var value=normalizePath(path);return value?resolvePath(value)+'?v='+Date.now():''}
