    function registerDelegatedEvents(){document.addEventListener('click',function(event){var target=event.target.closest('[data-action]');if(!target)return;event.preventDefault();runAction(target.getAttribute('data-action'),target)});document.addEventListener('keydown',function(event){var target=event.target;if(target&&target.id==='pf-tags'){pfTagKey(event);return}if(target&&(target.id==='pe-content'||target.id==='pg-content')){tabKey(event);return}if(target&&target.hasAttribute&&target.hasAttribute('data-enter-action')&&event.key==='Enter'){event.preventDefault();runAction(target.getAttribute('data-enter-action'),target);return}var pageTrigger=target&&target.closest?target.closest('[data-action="open-page-editor"]'):null;if(pageTrigger&&(event.key==='Enter'||event.key===' ')){event.preventDefault();runAction('open-page-editor',pageTrigger)}})}
